<template>
  <!-- Remove the v-app and v-app-bar here -->
  <!-- Assume that the header is already included via BaseLayout -->
  <v-container fluid>
    <v-row justify="center">
      <v-col cols="12" sm="8" md="6">
        <v-card class="pa-5" color="blue-grey-lighten-3">
          <v-card-title>Choose an Option</v-card-title>
          <v-card-text>
            <v-select
              v-model="selectedTemplate"
              :items="templates"
              item-title="label"
              item-value="filename"
              label="Select a Document Template"
              return-object
            ></v-select>

            <v-btn
              color="blue-grey-darken-4"
              class="ma-3"
              @click="navigateToInputFieldsPage"
              :disabled="!selectedTemplate"
            >
              Go to Input Fields Page
            </v-btn>
          </v-card-text>
        </v-card>
      </v-col>
    </v-row>
  </v-container>
</template>

<script>
import { ref, onMounted, defineComponent, watch } from 'vue';
import { useRouter } from 'vue-router';
import axios from 'axios';
import { useStore } from 'vuex';

export default defineComponent({
  setup() {
    const router = useRouter();
    const store = useStore();
    const templates = ref([]);
    const selectedTemplate = ref(null);

    onMounted(async () => {
      const category = router.currentRoute.value.query.category;
      console.log('Category received in UserOptionsPage:', category);

      if (!category) {
        console.error('No category received in route.');
        return;
      }

      try {
        const response = await axios.get(`/api/templates?collection=${category}`);
        console.log('Templates response:', response.data);

        if (Array.isArray(response.data)) {
          templates.value = response.data.map((template) => ({
            label: template.label,
            filename: template.filename,
          }));
          console.log('Templates structured:', templates.value);
        } else {
          console.error('Expected an array but got:', response.data);
        }
      } catch (error) {
        console.error('Error fetching templates:', error);
      }
    });

    watch(selectedTemplate, (newValue) => {
      console.log('selectedTemplate changed to:', newValue);
      // Optional: Reset Vuex dynamic inputs when the template changes
      store.dispatch('updateDynamicInputs', []); // Clear the inputs when a new template is selected
      store.dispatch('updateDropdownMenus', []); // Clear dropdowns
      store.dispatch('setDynamicDateFields', []); // Clear date fields
    });

    const logout = () => {
      router.push({ name: 'login' });
    };

    const navigateToInputFieldsPage = () => {
      if (!selectedTemplate.value) {
        alert('No template selected. Please select a template first.');
        return;
      }

      const filename = selectedTemplate.value.filename || selectedTemplate.value.label; // Ensure correct filename is dispatched
      console.log('Navigating to InputFieldsPage with template:', filename); // Add log here
      store.dispatch('updateSelectedTemplate', filename); // Dispatch the selected template filename to the store
      router.push({ name: 'inputFieldsPage' });
    };

    return {
      logout,
      templates,
      selectedTemplate,
      navigateToInputFieldsPage,
    };
  },
});
</script>
