<template>
    <v-container>
      <v-row justify="center">
        <v-col cols="12" sm="8" md="6">
          <v-card>
            <v-card-title>Select a Category</v-card-title>
            <v-card-text>
              <v-select
                v-model="selectedCategory"
                :items="categories"
                item-title="displayName"
                item-value="name"
                label="Select a Category"
              ></v-select>
              <v-btn
                :disabled="!selectedCategory"
                color="primary"
                @click="navigateToTemplateSelection"
                class="mt-4"
              >
                Proceed to Template Selection
              </v-btn>
            </v-card-text>
          </v-card>
        </v-col>
      </v-row>
    </v-container>
  </template>
  
  <script>
  import { ref, onMounted } from 'vue';
  import axios from 'axios';
  import { useRouter } from 'vue-router';
  
  export default {
    setup() {
      const categories = ref([]);
      const selectedCategory = ref(null);
      const router = useRouter();
  
      // Fetch collection names dynamically on component mount
      onMounted(async () => {
        try {
          const response = await axios.get('/api/collections');
          // Filter and format collection names for display
          categories.value = response.data
            .filter((name) => name.startsWith('cat_') && name.endsWith('.files'))
            .map((name) => ({
              name, // Original name for sending to the backend
              displayName: name.replace('cat_', '').replace('.files', ''), // User-friendly name
            }));
          console.log('Filtered categories:', categories.value);
        } catch (error) {
          console.error('Error fetching categories:', error);
        }
      });
  
      const navigateToTemplateSelection = () => {
        if (selectedCategory.value) {
          console.log('Navigating to template selection with category:', selectedCategory.value);
          router.push({ name: 'userOptionsPage', query: { category: selectedCategory.value } });
        } else {
          console.error('No category selected.');
        }
      };
  
      return {
        categories,
        selectedCategory,
        navigateToTemplateSelection,
      };
    },
  };
  </script>
  