<template>
  <div class="explorer-container">
    <!-- Left Pane: Folder Tree -->
    <div class="left-pane">
      <h3>CSE PROPOSALS</h3>
      <FolderNode
        v-for="folder in folderStructure"
        :key="folder.name"
        :folder="folder"
        @fetch-files="fetchFiles"
      />
    </div>

    <!-- Right Pane: File List -->
    <div class="right-pane">
      <h3>Files</h3>
      <div v-if="currentView === 'files' && files.length > 0">
        <div v-for="file in files" :key="file._id" class="file-item">
          <!-- Display file icon and info -->
          <div class="file-info">
            <v-icon class="file-icon">
              {{ file.contentType && file.contentType.startsWith('image') ? 'mdi-file-image' : 'mdi-file-document' }}
            </v-icon>
            <span>{{ file.filename }}</span>
            <span>Type: {{ file.contentType }}</span>
          </div>
          <!-- Display images -->
          <img v-if="file.contentType && file.contentType.startsWith('image')" 
               :src="`/api/files/${file._id}`" 
               alt="Image" 
               class="thumbnail" />
          <!-- File actions -->
          <div class="file-actions">
            <v-btn @click="downloadFile(file._id)" color="primary" class="ma-1">Download</v-btn>
            <v-btn @click="deleteFile(file._id)" color="error" class="ma-1">Delete</v-btn>
          </div>
        </div>
      </div>
      <div v-else>
        <p>No files available</p>
      </div>

      <!-- Upload Section -->
      <div class="upload-section">
        <h3>Upload to std_ Folder</h3>
        <v-select
          v-model="selectedStdFolder"
          :items="processedStdFolders"
          label="Select Folder"
          @change="onFolderSelect"
          class="ma-2"
        ></v-select>
        <input
          type="file"
          @change="onFileChange"
          accept=".doc,.docx,.xls,.xlsx,.txt,.pdf,image/*"
          class="ma-2"
        />
        <v-progress-linear
          v-if="isUploading"
          :indeterminate="true"
          color="blue"
          class="mb-2"
        ></v-progress-linear>
        <v-btn @click="uploadFile" :loading="isUploading" class="ma-2" color="primary">Upload</v-btn>
      </div>
    </div>
  </div>
</template>


<script>
import axios from 'axios';
import FolderNode from './FolderNode.vue';

export default {
  components: {
    FolderNode,
  },
  data() {
    return {
      folderStructure: [
        {
          name: "CSE PROPOSALS",
          children: [
            {
              name: "Admin",
              children: [
                { name: "Users", children: [] },
                { name: "UserLogs", children: [] },
              ],
            },
            {
              name: "ARTIFACTS",
              children: [
                {
                  name: "GOS_gridos",
                  children: [
                    { name: "std_architectures", children: [] },
                    { name: "std_contents", children: [] },
                    { name: "std_estimates", children: [] },
                    { name: "std_gantts", children: [] },
                    { name: "std_risks", children: [] },
                  ],
                },
                {
                  name: "NLF_networklife",
                  children: [
                    { name: "std_architectures", children: [] },
                    { name: "std_contents", children: [] },
                    { name: "std_estimates", children: [] },
                    { name: "std_gantts", children: [] },
                    { name: "std_risks", children: [] },
                  ],
                },
              ],
            },
            {
              name: "Generated_proposals",
              children: [],
            },
          ],
        },
      ],
      files: [],
      currentView: 'files',
      currentFolder: '', // Track the current folder
      selectedStdFolder: null, // New property for selected std_ folder
      selectedFile: null, // New property for the selected file
      isUploading: false,
      allStdFolders: [
        { value: 'GOS_gridos_std_architectures', title: 'GOS Gridos - Std Architectures' },
        { value: 'GOS_gridos_std_contents', title: 'GOS Gridos - Std Contents' },
        { value: 'GOS_gridos_std_estimates', title: 'GOS Gridos - Std Estimates' },
        { value: 'GOS_gridos_std_gantts', title: 'GOS Gridos - Std Gantts' },
        { value: 'GOS_gridos_std_risks', title: 'GOS Gridos - Std Risks' },
        { value: 'NLF_networklife_std_architectures', title: 'NLF Networklife - Std Architectures' },
        { value: 'NLF_networklife_std_contents', title: 'NLF Networklife - Std Contents' },
        { value: 'NLF_networklife_std_estimates', title: 'NLF Networklife - Std Estimates' },
        { value: 'NLF_networklife_std_gantts', title: 'NLF Networklife - Std Gantts' },
        { value: 'NLF_networklife_std_risks', title: 'NLF Networklife - Std Risks' },
      ],
    };
  },

  computed: {
  // Ensure this returns a simple array of objects
  processedStdFolders() {
    const folders = this.allStdFolders.map(folder => ({
      value: folder.value,
      title: folder.title
    }));
    console.log('Processed Folders:', folders);
    return folders;
  },

  computed: {
  getAcceptedFileTypes() {
    // Accept common file types
    return '.doc,.docx,.xls,.xlsx,.txt,image/*';
  },
},

},


  watch: {
  // Watch for changes in the selected folder
  selectedStdFolder(newVal) {
    console.log('Selected Folder:', newVal);
  },

},

methods: {


  fetchFiles(folderName) {
    this.currentFolder = folderName;
    console.log(`Fetching files for folder: ${folderName}`);

    // Check if the folder is one of the special folders
    const isSpecialFolder = 
      folderName === 'Admin_Users' || 
      folderName === 'Admin_UserLogs' || 
      folderName === 'Generated_proposals';

    // Use the appropriate endpoint based on the folder type
    const endpoint = isSpecialFolder ? 
      `/files/special/${encodeURIComponent(folderName)}` : 
      `/files/${encodeURIComponent(folderName)}`;

    axios.get(endpoint)
      .then(response => {
        if (response.data.type === 'files' && response.data.files.length > 0) {
          this.files = response.data.files;
          this.currentView = 'files';
        } else {
          this.files = [];
          console.log('No files available for this folder.');
        }
      })
      .catch(error => {
        console.error('Error fetching files:', error);
      });
  },
  downloadFile(fileId) {
    axios({
      url: `/api/files/${fileId}`,
      method: 'GET',
      responseType: 'blob', // Important
    })
      .then((response) => {
        const url = window.URL.createObjectURL(new Blob([response.data]));
        const link = document.createElement('a');
        link.href = url;

        // Get the filename from the headers or default to 'download'
        const contentDisposition = response.headers['content-disposition'];
        let fileName = 'download';
        if (contentDisposition) {
          const fileNameMatch = contentDisposition.match(/filename="?(.+)"?/);
          if (fileNameMatch.length === 2) fileName = fileNameMatch[1];
        }

        link.setAttribute('download', fileName);
        document.body.appendChild(link);
        link.click();
      })
      .catch((error) => {
        console.error('Error downloading file:', error);
      });
  },

  deleteFile(fileId) {
    if (!this.currentFolder) {
      console.error('No folder selected for deletion');
      return;
    }

    const isSpecialFolder = 
      this.currentFolder === 'Admin_Users' || 
      this.currentFolder === 'Admin_UserLogs' || 
      this.currentFolder === 'Generated_proposals';

    const deleteUrl = isSpecialFolder 
      ? `/api/delete-file/${encodeURIComponent(this.currentFolder)}/${fileId}`
      : `/api/delete-file/${encodeURIComponent(this.currentFolder)}/${fileId}`;

    axios.delete(deleteUrl)
      .then(response => {
        console.log(`File deleted from folder ${this.currentFolder}:`, response.data);
        this.fetchFiles(this.currentFolder); // Refresh the file list after deletion
      })
      .catch(error => {
        console.error('Error deleting file:', error.response ? error.response.data : error);
      });
  },


onFileChange(event) {
  this.selectedFile = event.target.files[0];

  if (this.selectedFile) {
    // Detect the file type
    const fileType = this.selectedFile.type;
    console.log('Detected File Type:', fileType);

    // Optionally, you can set a property if needed
    this.detectedFileType = fileType;
  }
},

  // New method to handle folder selection
  onFolderSelect() {
    console.log('Folder Selected:', this.selectedStdFolder);
  },
  // New method to handle file type selection
  onFileTypeSelect() {
    console.log('File Type Selected:', this.selectedFileType);
  },
  async uploadFile() {
      if (!this.selectedFile || !this.selectedStdFolder) {
        console.log('Upload aborted: Missing file or folder selection.');
        return;
      }

      this.isUploading = true; // Start upload progress

      const formData = new FormData();
      formData.append('file', this.selectedFile);

      try {
        const response = await axios.post(`/files/upload/${encodeURIComponent(this.selectedStdFolder)}`, formData);
        console.log(`File uploaded to ${this.selectedStdFolder}:`, response.data);
        this.fetchFiles(this.selectedStdFolder); // Refresh file list
      } catch (error) {
        console.error('Error uploading file:', error.response ? error.response.data : error);
      } finally {
        this.isUploading = false; // End upload progress
      }
    },

},

};
</script>

<style scoped>
.explorer-container {
  display: flex;
  height: 80vh;
}

.left-pane {
  width: 30%;
  padding: 10px;
  overflow-y: auto;
  border-right: 1px solid #ccc;
  background: #f9f9f9;
}

.file-info {
  display: flex;
  align-items: center;
}
.file-icon {
  margin-right: 8px;
}
.file-item:hover {
  background-color: #f0f0f0;
}

.folder-item,
.subfolder-item {
  margin: 5px 0;
  padding: 5px;
}

.right-pane {
  flex: 1;
  padding: 10px;
  overflow-y: auto;
}

.file-item {
  display: flex;
  justify-content: space-between;
  padding: 5px;
  border-bottom: 1px solid #ccc;
}

.folder-item:hover,
.subfolder-item:hover {
  background-color: #f0f0f0;
}

.thumbnail {
  width: 100px;
  height: 100px;
  object-fit: cover;
  margin: 5px;
}

.upload-section {
  margin-top: 20px;
}

.upload-section input {
  margin-bottom: 10px;
}

.v-btn {
  margin: 5px;
}

</style>
