<template>
  <v-app>
    <v-app-bar color="white" dark>
      <v-toolbar-title>Checkbox Page</v-toolbar-title>
    </v-app-bar>

    <v-main>
      <v-container fluid>
        <v-row justify="center">
          <v-col cols="12" sm="8" md="6">
            <v-subheader>Uncheck sections you want to exclude from the document.</v-subheader>

            <!-- Relocated Collapse/Expand All Button -->
            <div class="d-flex justify-center mb-4">
              <v-btn 
                @click="toggleAllSections" 
                class="ma-2" 
                small 
                outlined
              >
                <v-icon>{{ allCollapsed ? 'mdi-chevron-right' : 'mdi-chevron-down' }}</v-icon>
                {{ allCollapsed ? 'Expand All' : 'Collapse All' }}
              </v-btn>
            </div>

            <!-- Scrollable container -->
            <div class="checkbox-container">
              <div v-if="sections.length > 0">
                <SectionCheckbox
                  v-for="section in sections"
                  :key="section.id"
                  :section="section"
                  :all-collapsed="allCollapsed"
                  @update-checked="updateChecked"
                />
              </div>
            </div>

            <v-btn @click="submitData" :disabled="!isAnySectionChecked">Start Processing</v-btn>
          </v-col>
        </v-row>
      </v-container>
    </v-main>
  </v-app>
</template>

<script>
import { ref, onMounted, computed} from 'vue';
import axios from 'axios';
import { useRouter } from 'vue-router';
import { useStore } from 'vuex';
import Docxtemplater from 'docxtemplater';
import PizZip from 'pizzip';
import { saveAs } from 'file-saver';
import SectionCheckbox from './SectionCheckbox.vue';
import { onBeforeRouteLeave } from 'vue-router';
import { onUpdated } from 'vue';
import { toRaw } from 'vue';

// Define color options for parent sections
const colors = ['blue', 'green', 'purple', 'orange', 'teal'];

export default {
  components: {
    SectionCheckbox,
  },
  setup() {
    const router = useRouter();
    const store = useStore();

    const setIndeterminate = () => {
      sections.value.forEach(section => {
        if (section.indeterminate) {
          const checkbox = document.getElementById(section.id);
          if (checkbox) {
            checkbox.indeterminate = true;
          }
        }
      });
    };

    onUpdated(() => {
      setIndeterminate();
    });

    const allCollapsed = ref(false);

    // Retrieve `sections` from Vuex as a computed property
    const sectionsFromVuex = computed(() => store.state.sections);


    const sections = ref([]);
    const dynamicInputs = ref(store.state.dynamicInputs);
    const dropdownMenus = ref(store.state.dropdownMenus); // Retrieve dropdownMenus from Vuex
    const selectedSections = ref({});
    const selectedTemplate = computed(() => store.state.selectedTemplate);
    const dynamicDateFields = ref(store.state.dynamicDateFields); // Pull dynamic date fields from Vuex
    const tableData = ref(store.state.tableData); // Pull dynamic table data from Vuex
    let currentColorIndex = 0; // To track the current color index

    const isAnySectionChecked = computed(() =>
          sections.value.some((section) => section.checked || section.children.some(child => child.checked))
        );


      const toggleAllSections = () => {
      allCollapsed.value = !allCollapsed.value;
      sections.value.forEach((section) => {
        section.collapsed = allCollapsed.value;
        collapseChildren(section.children, allCollapsed.value);
      });
    };

    const collapseChildren = (children, collapsed) => {
      if (children && children.length > 0) {
        children.forEach((child) => {
          child.collapsed = collapsed;
          if (child.children.length > 0) {
            collapseChildren(child.children, collapsed);
          }
        });
      }
    };

    const ensureCheckedStatePropagation = (sections) => {
      // Since we want parents to be independent, we don't need to update their checked state based on children
      // However, we might still want to ensure children have valid states
      const validateChildren = (section) => {
        if (section.children && section.children.length > 0) {
          section.children.forEach(child => validateChildren(child));
        }
      };

      sections.forEach(section => validateChildren(section));
    };




    // Fetch and parse sections when the component is mounted
    onMounted(async () => {
      if (store.state.isNavigatingBack && sectionsFromVuex.value.length > 0) {
        console.log('Navigating back: Loading sections from Vuex.');
        sections.value = sectionsFromVuex.value;
        ensureCheckedStatePropagation(sections.value); // Ensure state is propagated correctly
        console.log('Sections loaded from Vuex and checked state verified:', sections.value);
      } else {
        console.log('Initial load or refresh: Fetching and parsing sections.');
        await fetchTemplateAndParseSections();
        assignColorsToSections(sections.value);
      }

      store.commit('setNavigatingBack', false);
    });


    onBeforeRouteLeave((to, from, next) => {
      store.commit('setNavigatingBack', true); // Set the flag to true when navigating away
      next(); // Proceed with the navigation
    });


    const fetchTemplateAndParseSections = async () => {
      try {
        const templateFilename = selectedTemplate.value;
        if (!templateFilename) {
          alert('No template selected. Please go back and select a template.');
          return;
        }

        const response = await axios.get(`/api/sow-template?filename=${encodeURIComponent(templateFilename)}`, {
          responseType: 'arraybuffer',
        });

        const content = response.data;
        const zip = new PizZip(content);
        const doc = new Docxtemplater(zip, {
          paragraphLoop: true,
          linebreaks: true,
        });

        // Parse the document sections
        const parsedSections = parseSections(doc);

        // Filter out the dropdown menus from the sections
        const filteredSections = parsedSections.filter(section => !section.id.startsWith('Select_'));
        sections.value = filteredSections;

        // Dispatch sections data to Vuex
        store.dispatch('updateSections', sections.value);
        console.log('Dispatched sections to Vuex:', sections.value);  // Log to confirm data structure and content


      } catch (error) {
        console.error('Error fetching and parsing template:', error);
        alert('Failed to load the document template. Please try again later.');
      }
    };

    // Assign colors to parent sections and propagate to children
    const assignColorsToSections = (sections, isFromVuex = false) => {
      // Only assign colors if sections are freshly parsed, not loaded from Vuex
      if (isFromVuex) {
        console.log('Skipping color assignment as sections are loaded from Vuex.');
        return;
      }

      sections.forEach((section) => {
        if (section.isParent) {
          section.color = colors[currentColorIndex % colors.length];
          console.log(`Assigned color '${section.color}' to parent section: ${section.label}`);
          currentColorIndex++;

          if (section.children.length > 0) {
            console.log(`Propagating color '${section.color}' to children of: ${section.label}`);
            assignColorToChildren(section.children, section.color);
          }
        }
      });
    };


    const assignColorToChildren = (children, color) => {
      children.forEach((child) => {
        child.color = color; // Inherit color from the parent
        console.log(`Assigned color '${color}' to child section: ${child.label}`);

        // Recursive call for nested children
        if (child.children.length > 0) {
          assignColorToChildren(child.children, color);
        }
      });
    };


    const parseSections = (doc) => {
      const text = doc.getFullText();
      const sectionRegex = /\{[#/](.*?)\}/g;
      const stack = [];
      let match;
      let root = { children: [] };
      let currentParent = root;

      while ((match = sectionRegex.exec(text)) !== null) {
        const tag = match[0];
        const name = match[1].trim();

        if (tag.startsWith('{#')) {
          const newSection = {
            id: name,
            label: name,
            checked: true,
            children: [],
            parent: currentParent,
            isParent: stack.length === 0, // Mark it as a main/parent section if stack is empty
          };
          currentParent.children.push(newSection);
          stack.push(newSection);
          currentParent = newSection;
        } else if (tag.startsWith('{/')) {
          if (stack.length === 0 || stack[stack.length - 1].id !== name) {
            console.error('Mismatched closing tag:', tag);
          } else {
            stack.pop();
            currentParent = currentParent.parent;
          }
        }
      }

      return root.children;
    };

    const updateChecked = (payload) => {
      const { id, checked } = payload;

      const updateSectionChecked = (sections) => {
        sections.forEach((section) => {
          if (section.id === id) {
            section.checked = checked;
          } 
          if (section.children && section.children.length > 0) {
            updateSectionChecked(section.children);
          }
        });
      };

      updateSectionChecked(sections.value);
      console.log("Updated sections:", sections.value);
      };


    const submitData = async () => {
      store.dispatch("updateSections", sections.value);
      console.log('Current Date:', store.state.currentDate);

      const traverseSections = (sections) => {
        sections.forEach((section) => {
          selectedSections.value[section.label] = section.checked;
          if (section.children && section.children.length > 0) {
            traverseSections(section.children);
          }
        });
      };

      traverseSections(sections.value);

      const dynamicInputsArray = dynamicInputs.value.map((input) => ({
        id: input.id,
        value: input.value,
      }));

      const dropdownData = dropdownMenus.value.map((dropdown) => ({
        id: dropdown.id,
        selectedOption: dropdown.selectedOption,
      }));

      console.log('Dropdown data before form submission:', dropdownData);

      const emptyTableTags = toRaw(store.state.emptyTableTags);

      try {
        console.log('Table data before spreading:', tableData.value);

        // Prepare data for docxtemplater
        let data = {
          ...Object.fromEntries(dynamicInputsArray.map((input) => [`input:${input.id}`, input.value])),
          currentDate: store.state.currentDate,
          ...selectedSections.value,
          ...tableData.value,  // Include the dynamic table data here
          ...emptyTableTags  
        };

        // Add dropdown selections to data
        dropdownData.forEach((dropdown) => {
          if (dropdown.selectedOption) {
            const key = `${dropdown.id} ${dropdown.selectedOption}`; // Adjust format for descriptive dropdowns
            data[key] = true;
          }
        });

        dynamicDateFields.value.forEach((dateField) => {
          console.log(`Processing date field for submission:`, dateField);
          // Add date, quarter, and year for each dateField
          data[`date:${dateField.id}`] = dateField.value;
          data[`quarter:${dateField.id}`] = dateField.quarter;
          data[`year:${dateField.id}`] = dateField.year;


          // Debugging logs for verification
          console.log(`Added date field to data: date:${dateField.id} = ${dateField.value}`);
          console.log(`Added quarter field to data: quarter:${dateField.id} = ${dateField.quarter}`);
          console.log(`Added year field to data: year:${dateField.id} = ${dateField.year}`);
        });

      
        console.log('Final data before sending to docxtemplater:', data);

        const templateResponse = await axios.get(`/api/sow-template?filename=${encodeURIComponent(selectedTemplate.value)}`, {
          responseType: 'arraybuffer',
        });

        const content = templateResponse.data;
        const zip = new PizZip(content);
        const doc = new Docxtemplater(zip, {
          paragraphLoop: true,
          linebreaks: true,
        });

        try {
          console.log('Final data before setting to docxtemplater:', data);
          doc.setData(data);
          doc.render();
        } catch (error) {
          console.error('Error rendering document:', error);
          alert('Failed to generate the document. Please check the template and try again.');
          return;
        }

        const out = doc.getZip().generate({
          type: 'blob',
          mimeType: 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
        });

        console.log('Document generated successfully.');

        const file = new File([out], 'GeneratedDocument_SOW.docx', {
          type: 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
        });

        const formData = new FormData();
        formData.append('file', file);

        console.log('Uploading the generated document to the server.');

        // Retrieve JWT token from localStorage
        const token = localStorage.getItem('jwtToken');
        console.log('JWT token:', token);

        const uploadResponse = await axios.post('/api/upload-generated-document', formData, {
          headers: {
            'Authorization': `Bearer ${token}`,
            'Content-Type': 'multipart/form-data',
          },
        });

        const fileId = uploadResponse.data.fileId;
        console.log('Generated document uploaded, file ID:', fileId);
        await store.dispatch('setFileId', fileId);

        saveAs(out, 'GeneratedDocument_SOW.docx');

        router.push({ name: 'ProcessingPage', params: { fileId: uploadResponse.data.fileId } });
      } catch (error) {
        console.error('Error saving data:', error);
        alert('Failed to save the data. Please try again later.');
      }
    };


    return {
      sections,
      submitData,
      dynamicInputs,
      dropdownMenus,
      updateChecked,
      selectedSections,
      tableData,
      isAnySectionChecked,
      toggleAllSections,
      allCollapsed,

    };
  },
};
</script>

<style scoped>
.checkbox-container {
  max-height: 400px; /* Set a fixed height */
  overflow-y: auto; /* Enable vertical scrolling */
  border: 1px solid #ccc; /* Optional border for visibility */
  padding: 8px; /* Padding inside the container */
}

.v-btn {
  font-size: 0.8rem; /* Reduce the button font size */
}

.v-icon {
  font-size: 6px; /* Adjust the icon size for collapse/expand buttons */
}
</style>