<template>
  <v-container fluid fill-height>
    <v-row class="fill-height" justify="center" align="center">
      <v-col cols="12" sm="8" md="6">
        <v-card outlined elevated>
          <v-card-text>
            <v-card-title>Login</v-card-title>
            <v-form @submit.prevent="handleSubmit">
              <v-text-field 
                v-model="username" 
                label="Username" 
                required 
                type="text"
                color="cyan"
                variant="solo"
              />
              <v-text-field 
                v-model="password" 
                label="Password" 
                required 
                type="password" 
                color="cyan"
                variant="solo"
              />
              <v-btn type="submit" color="primary">Login</v-btn>
            </v-form>
          </v-card-text>
        </v-card>
      </v-col>
    </v-row>
    <v-snackbar v-model="snackbar" :timeout="3000" color="success">
      {{ snackbarMessage }}
      <v-btn text @click="snackbar = false">Close</v-btn>
    </v-snackbar>
  </v-container>
</template>

<script>
import { mapMutations } from 'vuex';
import { useRouter } from 'vue-router';

export default {
  name: 'LogIn',
  data() {
    return {
      username: '',
      password: '',
      snackbar: false,
      snackbarMessage: '',
    };
  },
  setup() {
    const router = useRouter();
    return { router };
  },
  methods: {
    ...mapMutations(['setUser']), // Assuming you have a Vuex store mutation for setting user data

    // Handle form submission for login
    async handleSubmit() {
  console.log('handleSubmit called');
  try {
    const apiUrl = process.env.VUE_APP_API_URL || '/api';
    const response = await fetch(`${apiUrl}/login`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        username: this.username,
        password: this.password
      })
    });

    const data = await response.json();

    if (response.ok) {
      console.log('Login successful:', data);

      // Log the token received from the backend
      console.log('JWT token received:', data.token);

      // Store user information in localStorage
      localStorage.setItem('username', this.username);
      localStorage.setItem('jwtToken', data.token);

      // Store user information in Vuex store
      this.setUser(data.user);

      if (data.firstLogin) {
        console.log('User is logging in for the first time');
        this.router.replace({ name: 'welcomePage' });
      } else {
        if (data.user.role === 'Admin') {
          this.router.replace({ name: 'adminDashboard' });
        } else {
          this.router.replace({ name: 'selectCategory' });
        }
      }
    } else {
      // Handle invalid credentials
      this.snackbarMessage = 'Invalid username or password';
      this.snackbar = true;
    }
  } catch (error) {
    console.error('Error during login:', error);
    // Handle server error
    this.snackbarMessage = 'Server error';
    this.snackbar = true;
  }

  // Clear input fields after submission
  this.username = '';
  this.password = '';
}

  },
};
</script>
